 236→            const animGal = galaxyPositions.get(uid);
 237→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 238→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 239→            const pull = starPullOffsets.get(post.id);
 240→
 241→            const baseX = post.universe_x ?? post.display_x;
 242→            const baseY = post.universe_y ?? post.display_y;
 243→            if (baseX == null || baseY == null) continue;
 244→
 245→            let x = baseX + galDx + (pull?.dx ?? 0);
 246→            let y = baseY + galDy + (pull?.dy ?? 0);
 247→
 248→            map.set(post.id, { x, y });
 249→        }
 250→        return map;
