  3→export const requestConstellationService = async (senderId, starIdA, starIdB, label) => {
  4→    if (!senderId || !starIdA || !starIdB) {
  5→        throw { status: 400, error: 'senderId, starIdA, and starIdB are required' };
  6→    }
  7→
  8→    // Verify starIdA belongs to sender
  9→    const { data: starA, error: errorStarA } = await supabase
 10→        .from('journals')
 11→        .select('id, user_id')
 12→        .eq('id', starIdA)
 13→        .maybeSingle();
 14→
 15→    if (errorStarA) {
 16→        console.error('supabase error checking starA ownership:', errorStarA.message);
 17→        throw { status: 500, error: 'error checking star ownership' };
 18→    }
 19→    if (!starA || starA.user_id !== senderId) {
 20→        throw { status: 403, error: 'starIdA does not belong to you' };
 21→    }
 22→
 23→    // Get starIdB owner
 24→    const { data: starB, error: errorStarB } = await supabase
 25→        .from('journals')
 26→        .select('id, user_id')
 27→        .eq('id', starIdB)
 28→        .maybeSingle();
 29→
 30→    if (errorStarB) {
 31→        console.error('supabase error checking starB:', errorStarB.message);
 32→        throw { status: 500, error: 'error checking target star' };
 33→    }
 34→    if (!starB) {
 35→        throw { status: 404, error: 'target star not found' };
 36→    }
 37→
 38→    const receiverId = starB.user_id;
 39→    if (receiverId === senderId) {
 40→        throw { status: 400, error: 'cannot create constellation with your own stars' };
 41→    }
 42→
 43→    // Normalize pair order to avoid duplicate check issues
 44→    const [normA, normB] = starIdA < starIdB ? [starIdA, starIdB] : [starIdB, starIdA];
 45→    const [normUserA, normUserB] = starIdA < starIdB ? [senderId, receiverId] : [receiverId, senderId];
 46→
 47→    // Insert constellation
 48→    const { data: constellation, error: errorInsert } = await supabase
 49→        .from('constellations')
 50→        .insert({
 51→            star_id_a: normA,
 52→            star_id_b: normB,
 53→            user_id_a: normUserA,
 54→            user_id_b: normUserB,
 55→            label: label || '',
 56→            status: 'pending',
 57→        })
 58→        .select()
 59→        .single();
 60→
 61→    if (errorInsert) {
 62→        if (errorInsert.code === '23505') {
 63→            throw { status: 409, error: 'a constellation link between these stars already exists' };
 64→        }
 65→        console.error('supabase error inserting constellation:', errorInsert.message);
 66→        throw { status: 500, error: 'error creating constellation' };
 67→    }
 68→
 69→    // Insert notification for the receiver
 70→    const { error: errorNotif } = await supabase
 71→        .from('notifications')
 72→        .insert({
 73→            sender_id: senderId,
 74→            receiver_id: receiverId,
 75→            journal_id: starIdB,
 76→            type: 'constellation_request',
 77→            constellation_id: constellation.id,
 78→            read: false,
 79→        });
 80→
 81→    if (errorNotif) {
 82→        console.error('supabase error inserting constellation notification:', errorNotif.message);
 83→    }
 84→
 85→    return { message: 'constellation request sent', constellationId: constellation.id };
 86→};
 87→
 88→export const respondConstellationService = async (userId, constellationId, accept) => {
 89→    if (!userId || !constellationId) {
 90→        throw { status: 400, error: 'userId and constellationId are required' };
 91→    }
 92→
 93→    const { data: constellation, error: errorFetch } = await supabase
 94→        .from('constellations')
 95→        .select('*')
 96→        .eq('id', constellationId)
 97→        .maybeSingle();
 98→
 99→    if (errorFetch) {
100→        console.error('supabase error fetching constellation:', errorFetch.message);
101→        throw { status: 500, error: 'error fetching constellation' };
102→    }
103→    if (!constellation) {
104→        throw { status: 404, error: 'constellation not found' };
105→    }
106→    if (constellation.status !== 'pending') {
107→        throw { status: 400, error: 'constellation has already been responded to' };
108→    }
109→
110→    // The responder must be the user who did NOT initiate
111→    const isRecipient = constellation.user_id_a === userId || constellation.user_id_b === userId;
112→    if (!isRecipient) {
113→        throw { status: 403, error: 'you are not a participant of this constellation' };
114→    }
115→
116→    // Determine who the initiator was (the sender of the request notification)
117→    // The initiator is the one who is NOT the current user responding
118→    const initiatorId = constellation.user_id_a === userId ? constellation.user_id_b : constellation.user_id_a;
119→
120→    const newStatus = accept ? 'accepted' : 'declined';
121→
122→    const { error: errorUpdate } = await supabase
123→        .from('constellations')
124→        .update({ status: newStatus })
125→        .eq('id', constellationId);
126→
127→    if (errorUpdate) {
128→        console.error('supabase error updating constellation:', errorUpdate.message);
129→        throw { status: 500, error: 'error updating constellation status' };
130→    }
131→
132→    // If accepted, notify the initiator
133→    if (accept) {
134→        const { error: errorNotif } = await supabase
135→            .from('notifications')
136→            .insert({
137→                sender_id: userId,
138→                receiver_id: initiatorId,
139→                journal_id: constellation.star_id_a,
140→                type: 'constellation_accepted',
141→                constellation_id: constellationId,
142→                read: false,
143→            });
144→
145→        if (errorNotif) {
146→            console.error('supabase error inserting acceptance notification:', errorNotif.message);
147→        }
148→    }
149→
150→    return { message: accept ? 'constellation accepted' : 'constellation declined' };
151→};
